import{_ as o,c as a,o as l,aj as i}from"./chunks/framework.CjkNaYQl.js";const b=JSON.parse('{"title":"4. 自主練習","description":"","frontmatter":{},"headers":[],"relativePath":"intermediate/4.md","filePath":"intermediate/4.md"}'),t={name:"intermediate/4.md"};function c(d,e,r,s,h,n){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_4-自主練習" tabindex="-1">4. 自主練習 <a class="header-anchor" href="#_4-自主練習" aria-label="Permalink to &quot;4. 自主練習&quot;">​</a></h1><h2 id="題目一-迴圈" tabindex="-1">題目一：迴圈 <a class="header-anchor" href="#題目一-迴圈" aria-label="Permalink to &quot;題目一：迴圈&quot;">​</a></h2><p>用與<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>相同題目，但重覆執行六次。</p><h2 id="驗證一" tabindex="-1">驗證一 <a class="header-anchor" href="#驗證一" aria-label="Permalink to &quot;驗證一&quot;">​</a></h2><ol><li>麻將放置板放置位置不固定，看手臂是否有辦法精準將麻將放到板中凹槽並重複六次（建議板子放置不要超過 180°）</li><li>在重複執行六次後，是否自動退出專案執行畫面</li></ol><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>在執行迴圈時，記得將麻將塊拿起來，否則會撞機。</p></div><h2 id="答案一" tabindex="-1">答案一 <a class="header-anchor" href="#答案一" aria-label="Permalink to &quot;答案一&quot;">​</a></h2><p>在<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>的基礎上，接續下去。</p><ol><li>新增一個計數用的變數</li><li><code>Set</code>：在最後一個放開夾爪（<code>DO_0</code> 為 <code>L</code>），設定變數 <code>+= 1</code></li><li><code>If</code>：建立迴圈（例如設定變數條件為 <code>&gt;= 6</code>） <ul><li><code>Yes</code>：與<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>後續相同，讓專案結束</li><li><code>No</code>：利用 <code>Goto</code> 連接回 <code>If</code>，使迴圈封閉（或者可直接拉出流程線接回去，而不使用 <code>Goto</code>）</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>變數的計數方法和 <code>If</code> 條件可以用非常多種寫法，此處僅展示出其中一種。</p></div><h2 id="題目二-放滿板子" tabindex="-1">題目二：放滿板子 <a class="header-anchor" href="#題目二-放滿板子" aria-label="Permalink to &quot;題目二：放滿板子&quot;">​</a></h2><p>將六塊麻將塊依序放置於六個凹槽的板子上（放麻將的小板子），且板子位置會在範圍內不固定變換。</p><h2 id="驗證二" tabindex="-1">驗證二 <a class="header-anchor" href="#驗證二" aria-label="Permalink to &quot;驗證二&quot;">​</a></h2><ol><li>麻將位置不固定，看手臂是否能精準夾起麻將</li><li>放麻將的小板子位置不固定，看麻將塊是否能夠依序填滿六個格子（尤其中間排的格子）</li><li>填滿六個格子後，是否自動退出專案執行畫面</li></ol><h2 id="答案二" tabindex="-1">答案二 <a class="header-anchor" href="#答案二" aria-label="Permalink to &quot;答案二&quot;">​</a></h2><p>在完成<a href="#題目一迴圈">題目一：迴圈</a>的基礎上，接續下去。</p><ol><li><code>Pallet</code>（Vision Base）：替換原本「放置用的 <code>Point</code>」成 <code>Pallet</code></li><li>其餘部分都不用動它</li></ol><h2 id="題目三-疊高高" tabindex="-1">題目三：疊高高 <a class="header-anchor" href="#題目三-疊高高" aria-label="Permalink to &quot;題目三：疊高高&quot;">​</a></h2><p>將麻將塊以堆疊的方式，在同一個地方垂直向上堆疊三至五塊，且在螢幕上實時顯示目前已疊放了幾顆麻將。</p><h2 id="驗證三" tabindex="-1">驗證三 <a class="header-anchor" href="#驗證三" aria-label="Permalink to &quot;驗證三&quot;">​</a></h2><ol><li>麻將塊放置位置不固定，看手臂是否有辦法精準夾到麻將</li><li>麻將是否有辦法循環夾取，並放置於同一位置，且不觸發撞機報錯</li><li>流程結束後，是否自動退出專案執行畫面</li></ol><h2 id="答案三" tabindex="-1">答案三 <a class="header-anchor" href="#答案三" aria-label="Permalink to &quot;答案三&quot;">​</a></h2><p>在完成<a href="#題目一迴圈">題目一：迴圈</a>的基礎上，接續下去。</p><ol><li>更改 <code>If</code> 條件，讓它能夠迴圈跑你想要的次數（三至五次）</li><li>更改「放開 + 變數加一的 <code>Set</code>」，將坐標參數化也一併加入其中</li><li><code>Display</code>：可以在迴圈的第一步加入顯示資訊的功能，以達成「實時顯示目前已疊放了幾顆麻將」的要求</li></ol><h2 id="題目四-自選格子" tabindex="-1">題目四：自選格子 <a class="header-anchor" href="#題目四-自選格子" aria-label="Permalink to &quot;題目四：自選格子&quot;">​</a></h2><p>前面一樣去夾起不固定位置的麻將，但在放置到放麻將的小板子時，讓使用者可以自由選擇想要六格中的哪一格，再繼續剩下的放置與結束流程。</p><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>題目不要求迴圈功能，但若想延伸自主練習，你也可以讓專案跑到六格都被選到為止，且若使用者選擇被選過的位置，就不執行它，並顯示出錯誤訊息。</p></div><h2 id="驗證四" tabindex="-1">驗證四 <a class="header-anchor" href="#驗證四" aria-label="Permalink to &quot;驗證四&quot;">​</a></h2><ol><li>麻將位置不固定，看手臂是否能精準夾起麻將</li><li>在夾起麻將後，是否跳出包含六個選項的人機交互視窗供使用者選擇</li><li>使用者選擇位置後，是否能夠讓麻將被放置到對應的位置（放置麻將的板子位置不固定）</li><li>流程結束後，是否自動退出專案執行畫面</li></ol><h2 id="答案四" tabindex="-1">答案四 <a class="header-anchor" href="#答案四" aria-label="Permalink to &quot;答案四&quot;">​</a></h2><p>在<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>的基礎上，接續下去。</p><ol><li><code>M-Decision</code>：將原本「放置用的 <code>Point</code>」前，增加一個 <code>M-Decision</code> 節點，並且增加到六個選項（可自行命名），每個選項分支都要對應一個 <code>Point</code>（Vision Base）</li></ol><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>若想要完成題目的延伸功能，則可以讓專案跑六次迴圈，並且建立六個變數來記錄六個位置是否被選過，之後再用 <code>If</code> 來決定被選過的要跳提示訊息（<code>Display</code>）、沒放過的要放到該點位（<code>Point</code>）。</p><p><code>M-Decision</code> 的六個分支可以只改變 <code>Point</code>，剩下共用的部分（如 <code>Set</code>、<code>Wait for</code> 等）皆可接回同一個地方。</p></div>',33)])])}const u=o(t,[["render",c]]);export{b as __pageData,u as default};
